+// ─── Torch drawing with animated flame and glow ─────────────────────────────
+
+function drawTorch(ctx: CanvasRenderingContext2D, x: number, y: number, frame: number) {
+  // Torch handle and holder
+  ctx.fillStyle = '#4a4a58'; ctx.fillRect(x + 1, y + 10, 6, 4); ctx.fillRect(x + 5, y + 8, 3, 8);
+  ctx.fillStyle = '#4a2810'; ctx.fillRect(x + 2, y + 4, 4, 14);
+  ctx.fillStyle = '#5c3418'; ctx.fillRect(x + 3, y + 5, 2, 12);
+
+  // Animated flame layers
+  const f1 = Math.sin(frame * 0.2) * 2;
+  const f2 = Math.cos(frame * 0.25) * 1.5;
+  const f3 = Math.sin(frame * 0.3 + 1);
+
+  ctx.fillStyle = '#c05020';
+  ctx.fillRect(x + f2, y - 4, 8, 10);
+  ctx.fillStyle = '#e08030';
+  ctx.fillRect(x + 1 + f1, y - 6, 6, 10);
+  ctx.fillStyle = '#f0b040';
+  ctx.fillRect(x + 2 + f3, y - 7, 4, 8);
+  ctx.fillStyle = '#ffe890';
+  ctx.fillRect(x + 3, y - 5, 2, 4);
+
+  // Radial glow effect around the torch flame
+  const glowRadius = 24 + Math.sin(frame * 0.15) * 4;
+  const grd = ctx.createRadialGradient(x + 4, y, 0, x + 4, y, glowRadius);
+  grd.addColorStop(0, 'rgba(255, 180, 60, 0.12)');
+  grd.addColorStop(1, 'rgba(255, 180, 60, 0)');
+  ctx.fillStyle = grd;
+  ctx.fillRect(x + 4 - glowRadius, y - glowRadius, glowRadius * 2, glowRadius * 2);
+}
+
+// ─── Room lighting with torch point lights ───────────────────────────────────
+
+function drawRoomLighting(ctx: CanvasRenderingContext2D, type: CharacterType, x: number, y: number, w: number, h: number) {
+  const cs = Math.max(w, h) * 0.4;
+
+  // Base ambient corner lights
+  for (const [cx, cy] of [[x, y], [x + w, y], [x, y + h], [x + w, y + h]] as [number, number][]) {
+    const g = ctx.createRadialGradient(cx, cy, 0, cx, cy, cs);
+    g.addColorStop(0, 'rgba(0,0,0,0.2)');
+    g.addColorStop(1, 'rgba(0,0,0,0)');
+    ctx.fillStyle = g;
+    ctx.fillRect(Math.max(x, cx - cs), Math.max(y, cy - cs), cs, cs);
+  }
+
+  // Additional ambient glow for healer and king rooms
+  if (type === 'healer' || type === 'king') {
+    const g = ctx.createRadialGradient(x + w / 2, y + h * 0.5, 0, x + w / 2, y + h * 0.5, w * 0.45);
+    g.addColorStop(0, 'rgba(255, 200, 100, 0.04)');
+    g.addColorStop(1, 'rgba(255, 200, 100, 0)');
+    ctx.fillStyle = g;
+    ctx.fillRect(x, y, w, h);
+  }
+
+  // Torch positions per room type for point lights
+  const torchPositions: [number, number][] = [];
+  switch(type) {
+    case 'king':
+      torchPositions.push([x + w * 0.02, y + h * 0.15], [x + w * 0.92, y + h * 0.15]);
+      break;
+    case 'nobility':
+      torchPositions.push([x + w * 0.02, y + h * 0.12]);
+      break;
+    case 'knight':
+      torchPositions.push([x + w * 0.5, y + h * 0.06]);
+      break;
+    case 'scribe':
+      // No torches drawn explicitly in drawScriptorium, no lights
+      break;
+    case 'blacksmith':
+      torchPositions.push([x + w * 0.38, y + h * 0.06]);
+      break;
+    case 'workshop':
+      torchPositions.push([x + w * 0.88, y + h * 0.1]);
+      break;
+    case 'healer':
+      // No torches drawn explicitly in drawSanctum, no lights
+      break;
+    case 'sentinel':
+      torchPositions.push([x + w * 0.02, y + h * 0.28], [x + w * 0.9, y + h * 0.28]);
+      break;
+    case 'judge':
+      torchPositions.push([x + w * 0.08, y + h * 0.15], [x + w * 0.85, y + h * 0.15]);
+      break;
+    default:
+      break;
+  }
+
+  // Draw radial glow for each torch position
+  for (const [tx, ty] of torchPositions) {
+    const glowRadius = Math.min(w, h) * 0.15;
+    const gradient = ctx.createRadialGradient(tx, ty, 0, tx, ty, glowRadius);
+    gradient.addColorStop(0, 'rgba(255, 180, 60, 0.15)');
+    gradient.addColorStop(1, 'rgba(255, 180, 60, 0)');
+    ctx.fillStyle = gradient;
+    ctx.fillRect(tx - glowRadius, ty - glowRadius, glowRadius * 2, glowRadius * 2);
+  }
+}
